1. Import React hooks (useState, useEffect) for managing state
2. Use sun and moon SVG icons to visually represent the current theme
3. Include a button that toggles between themes on click
4. Apply smooth transitions when toggling between icons
5. Use Tailwind classes for styling that work with both light and dark modes

Pseudo-code:
```tsx
'use client';
import { useState, useEffect } from 'react';

export function DarkModeToggle() {
  const [isDark, setIsDark] = useState(true);

  // Effect to read initial theme from HTML element
  useEffect(() => {
    const htmlElement = document.documentElement;
    setIsDark(htmlElement.classList.contains('dark'));
  }, []);

  const toggleTheme = () => {
    const newTheme = !isDark;
    setIsDark(newTheme);
    // Theme toggle logic will be handled by the hook (task 2)
  };

  return (
    <button
      onClick={toggleTheme}
      className="p-2 rounded-lg hover:bg-zinc-800 transition-colors"
      aria-label="Toggle dark mode"
    >
      {isDark ? <SunIcon /> : <MoonIcon />}
    </button>
  );
}
```

Create a new hook file at `/home/opti3/services/ai-dev/apps/dashboard/hooks/useTheme.ts`. This hook should:

1. Initialize theme from localStorage on mount, falling back to 'dark' as default
2. Provide a toggle function that switches between light and dark modes
3. Update the HTML element's class list when theme changes
4. Persist theme preference to localStorage
5. Handle SSR compatibility by checking for window object

Pseudo-code:
```tsx
import { useState, useEffect } from 'react';

const STORAGE_KEY = 'theme-preference';

export function useTheme() {
  const [theme, setTheme] = useState<'light' | 'dark'>('dark');

  // Initialize theme from localStorage
  useEffect(() => {
    if (typeof window === 'undefined') return;

    const stored = localStorage.getItem(STORAGE_KEY);
    const initial = stored === 'light' ? 'light' : 'dark';
    setTheme(initial);

    // Apply initial theme
    const html = document.documentElement;
    html.classList.toggle('dark', initial === 'dark');
  }, []);

  // Update HTML class and localStorage when theme changes
  useEffect(() => {
    if (typeof window === 'undefined') return;

    const html = document.documentElement;
    html.classList.toggle('dark', theme === 'dark');
    localStorage.setItem(STORAGE_KEY, theme);
  }, [theme]);

  const toggleTheme = () => {
    setTheme(prev => prev === 'dark' ? 'light' : 'dark');
  };

  return { theme, toggleTheme };
}
```

